    private String getAuthType(String authHeader) {
        if (authHeader.startsWith("Bearer ")) {
            return "Bearer Token (OAuth/JWT)";
        } else if (authHeader.startsWith("Basic ")) {
            return "Basic Auth";
        } else if (authHeader.startsWith("Digest ")) {
            return "Digest Auth";
        } else if (authHeader.startsWith("HMAC ")) {
            return "HMAC";
        } else {
            return "Custom/Unknown";
        }
    }

    private String getStatusEmoji(int code) {
        if (code >= 200 && code < 300) return "✅";
        if (code >= 300 && code < 400) return "↪️";
        if (code == 401) return "🔒";
        if (code == 403) return "🚫";
        if (code == 404) return "🔍";
        if (code == 429) return "🚦";
        if (code >= 400 && code < 500) return "⚠️";
        if (code >= 500) return "🔥";
        return "❓";
    }

    private boolean isReadableBody(MediaType contentType) {
        if (contentType == null) return true;

        String type = contentType.type();
        String subtype = contentType.subtype();

        if ("text".equals(type)) return true;
        if ("application".equals(type)) {
            return "json".equals(subtype)
                    || "xml".equals(subtype)
                    || "javascript".equals(subtype)
                    || "x-www-form-urlencoded".equals(subtype)
                    || "graphql".equals(subtype)
                    || subtype.endsWith("+json")
                    || subtype.endsWith("+xml");
        }
        return false;
    }

    private Charset getCharset(MediaType contentType) {
        if (contentType != null) {
            Charset charset = contentType.charset(UTF8);
            if (charset != null) return charset;
        }
        return UTF8;
    }

    private String categorizeError(Exception e) {
        String className = e.getClass().getSimpleName();
        String message = e.getMessage() != null ? e.getMessage().toLowerCase() : "";

        if (className.contains("Timeout") || message.contains("timeout")) {
            return "TIMEOUT - Server took too long to respond";
        }
        if (className.contains("UnknownHost") || message.contains("unable to resolve host")) {
            return "DNS_FAILURE - Cannot resolve hostname (check internet/DNS)";
        }
        if (className.contains("ConnectException") || message.contains("failed to connect")) {
            return "CONNECTION_REFUSED - Server refused connection";
        }
        if (className.contains("SSLException") || className.contains("CertificateException") || message.contains("ssl") || message.contains("certificate")) {
            return "SSL_ERROR - SSL/TLS handshake or certificate problem";
        }
        if (className.contains("SocketException") || message.contains("connection reset") || message.contains("broken pipe")) {
            return "CONNECTION_LOST - Connection was interrupted";
        }
        if (message.contains("canceled")) {
            return "CANCELED - Request was canceled by client";
        }

        return "UNKNOWN - " + className;
    }

    private void logByStatusCode(int code, String message) {
        if (code >= 500) {
            Log.e(TAG, message);
        } else if (code >= 400) {
            Log.w(TAG, message);
        } else {
            Log.d(TAG, message);
        }
    }

    private void notifyCallback(String logMessage) {
        if (callback != null) {
            try {
                callback.onLog(logMessage);
            } catch (Exception e) {
                Log.e(TAG, "Error in log callback", e);
            }
        }
    }

